/* Suzume Doors — game engine */
(function () {
  const $ = s => document.querySelector(s);
  const LEVELS = [
    {
      bg: 'assets/bg-greenhouse.jpg', name: 'The Sunken Greenhouse', jp: '水没した温室',
      game: 'chair', diff: 'Medium', door: { x: 46.5, y: 34, w: 8, h: 56 },
      vid: { s: 0, e: 65 }, vidcap: 'A girl named Suzume meets a young man searching for a door — and finds one standing alone in the ruins.',
      brief: 'An abandoned school, drowned in still water. The ruins remember the children who ran here — listen to their voices, and echo them back, and the gate will know you mourn it.',
      quote: 'I humbly return what was once yours.'
    },
    {
      bg: 'assets/bg-resort.jpg', name: 'The Overgrown Springs', jp: '廃れた温泉街',
      game: 'daijin', diff: 'Medium', door: { x: 51.5, y: 49, w: 9, h: 32 },
      vid: { s: 65, e: 130 }, vidcap: 'A keystone pulled free becomes a small white cat — Daijin — and skips away laughing.',
      brief: 'A resort the forest has taken back. Daijin keeps splitting into mischievous shadows here, and only the true keystone will stay long enough to catch. Read the movement, ignore the decoys, and claim the real cat before the gate slips away.',
      quote: 'Suzume… I like you.'
    },
    {
      bg: 'assets/bg-school.jpg', name: 'The Flooded Schoolyard', jp: '水没した校庭',
      game: 'voices', diff: 'Low', door: { x: 49.7, y: 61, w: 8, h: 30 },
      vid: { s: 130, e: 195 }, vidcap: 'Souta is bound into a little three-legged chair. To open the doors, the chair must run.',
      brief: 'A glass conservatory drowned in clear water, one white door still standing within it. Daijin has lured the three-legged chair into a chase — hop the rubble, duck the crows, and reach the door across the water.',
      quote: 'O wrathful spirits — calm your anger and rest.'
    },
    {
      bg: 'assets/scene-flooded.png', name: 'The Flooded Crossing', jp: '水底の戸口',
      game: 'catrace', diff: 'Hard', door: { x: 49.8, y: 56, w: 14, h: 54 },
      vid: { s: 195, e: 260 }, vidcap: 'Daijin will not be caught so easily — if you want this door, you will have to outrun him.',
      brief: 'A lone door on a sheet of still water, and Daijin waiting beside a track of shifting reflections. Slash through the flooded lanes, chain fish boosts, and survive the broken gates and whirlpools long enough to beat him to the threshold.',
      quote: 'These mountains and rivers — I give back to their gods.'
    },
    {
      bg: 'assets/bg-mountain.png', ever: true, name: 'The Ever-After', jp: '常世',
      game: 'finale', diff: 'Hard', door: { x: 50, y: 62, w: 10, h: 33 },
      vid: { s: 260, e: 342 }, vidcap: 'At the last gate all times meet at once, and every star that ever fell is still falling. Open it, and dawn will come.',
      brief: 'The final door waits beneath a sky of endless stars. Break the Worm, align the hidden lock, and hold the key through the last surge. Whatever pushes back now is everything at once.',
      quote: 'No matter how long the night, dawn will come. We will meet again.'
    }
  ];
  const sfx = SuzumeAudio.sfx;
  let levelIdx = 0, mgCleanup = null, started = false, isCutscenePlaying = false;
  let runStats = makeRunStats();
  let gateFlawless = true;

  const MODES = ['Memory', 'Illusion', 'Chase', 'Calm'];
  const POOL = ['whisperSequence', 'daijin', 'chair', 'catrace', 'words', 'finale', 'doorSymbol', 'floodEscape', 'mirrorWorld', 'puzzle', 'timeFreeze', 'lightShadow', 'glitchMaze', 'fallingDebris', 'sentenceBuild', 'soundHunt', 'memoryTrail', 'chaseRunner', 'finalRitual', 'realityChoiceDoor', 'melodySeal'];

  let run = {
    difficulty: 'Medium',
    hiddenMode: 'Calm',
    mistakesAllowed: 3,
    mistakesUsed: 0,
    selectedMinigames: []
  };
  const CAT_HTML = '<svg style="width:54px;height:54px;filter:drop-shadow(0 0 12px rgba(255,255,255,.3));" viewBox="0 0 64 64" aria-hidden="true"><path d="M20 26 L17 9 L27 19 Q32 17 37 19 L47 9 L44 26 Q50 33 48 42 Q46 54 32 56 Q18 54 16 42 Q14 33 20 26 Z" fill="#f4f2ec"></path><circle cx="26" cy="34" r="2.6" fill="#243038"></circle><circle cx="38" cy="34" r="2.6" fill="#243038"></circle><path d="M29 41 Q32 44 35 41" stroke="#243038" stroke-width="1.6" fill="none"></path></svg>';

  /* ——— stage scaling ——— */
  const stage = $('#stage');
  function fit() {
    const s = Math.min(innerWidth / 1920, innerHeight / 1080);
    stage.style.transform = `translate(-50%,-50%) scale(${s})`;
  }
  addEventListener('resize', fit); fit();

  /* ——— helpers ——— */
  function show(id) {
    document.querySelectorAll('.screen').forEach(s => s.classList.remove('on'));
    $(id).classList.add('on');
  }
  function card(html) {
    const c = $('#level-card');
    c.innerHTML = html; c.style.display = 'flex';
    c.classList.remove('crise'); void c.offsetWidth; c.classList.add('crise');
    return c;
  }
  function hideCard() { $('#level-card').style.display = 'none'; }
  function saveProgress(n) { try { localStorage.setItem('suzume-doors-gate', String(n)); } catch (e) { } }
  function loadProgress() { try { return +(localStorage.getItem('suzume-doors-gate') || 0); } catch (e) { return 0; } }
  function makeRunStats() {
    return { startedAt: 0, fails: 0, mistakesSpent: 0, perfectDoors: 0, gatesCleared: 0, continued: false };
  }
  function beginRun(continued, difficulty = 'Medium') {
    runStats = makeRunStats();
    runStats.startedAt = Date.now();
    runStats.continued = !!continued;

    if (!continued || run.selectedMinigames.length < 5) {
      run.difficulty = difficulty;
      run.mistakesAllowed = difficulty === 'Easy' ? 5 : (difficulty === 'Dangerous' ? 2 : 3);
      run.mistakesUsed = 0;
      run.hiddenMode = MODES[Math.floor(Math.random() * MODES.length)];

      let shuffled = [...POOL].sort(() => Math.random() - 0.5);
      run.selectedMinigames = shuffled.slice(0, 5);

      console.log(`[DEBUG] Run Started -> Mode: ${run.hiddenMode}, Diff: ${run.difficulty}, Games:`, run.selectedMinigames);
    }

    document.body.className = `mode-${run.hiddenMode.toLowerCase()}`;
  }
  function formatDuration(ms) {
    const total = Math.max(0, Math.round(ms / 1000));
    const mins = Math.floor(total / 60);
    const secs = String(total % 60).padStart(2, '0');
    return `${mins}:${secs}`;
  }
  function victoryTone() {
    if (runStats.perfectDoors === LEVELS.length && runStats.fails === 0) return {
      kicker: 'Every door yielded in one breath',
      headline: 'A flawless closing',
      copy: 'You crossed the ruins without a single retreat. Even the Ever-After answered on the first try.'
    };
    if (runStats.fails >= 6) return {
      kicker: 'You kept coming back',
      headline: 'Morning, hard-won',
      copy: 'The doors resisted, the road bit back, and you still reached the dawn. That stubbornness is what saved this world.'
    };
    return {
      kicker: 'All five doors are sealed',
      headline: 'The morning comes',
      copy: 'The Ever-After is quiet again, and every door you touched now rests in peace.'
    };
  }
  function renderVictoryStats() {
    const tone = victoryTone();
    const elapsed = runStats.startedAt ? formatDuration(Date.now() - runStats.startedAt) : '0:00';
    $('#victory-kicker').textContent = tone.kicker;
    $('#victory-headline').textContent = tone.headline;
    $('#victory-quote').innerHTML = '“No matter how long the night, dawn will come.<br>We will meet again.”';
    $('#victory-copy').textContent = tone.copy;
    $('#victory-stats').innerHTML = [
      { label: 'Doors Sealed', value: String(runStats.gatesCleared || LEVELS.length) },
      { label: 'Perfect Gates', value: String(runStats.perfectDoors) },
      { label: 'Second Chances', value: String(runStats.fails) },
      { label: 'Journey Time', value: elapsed }
    ].map(stat => `<div class="victory-stat"><strong>${stat.value}</strong><span>${stat.label}</span></div>`).join('');
  }

  /* ——— HUD ——— */
  function renderHud() {
    const L = LEVELS[levelIdx];
    $('#hud-loc').textContent = `Gate ${levelIdx + 1} — ${L.name}`;
    $('#hud-jp').textContent = L.jp;

    const remaining = run.mistakesAllowed - run.mistakesUsed;
    let html = '';
    for (let i = 0; i < run.mistakesAllowed; i++) {
      html += `<div class="charm${i >= remaining ? ' spent' : ''}"></div>`;
    }
    $('#charms').innerHTML = html;
    $('#progress').innerHTML = LEVELS.map((_, i) =>
      `<div class="pdoor${i < levelIdx ? ' locked' : ''}${i === levelIdx ? ' now' : ''}"></div>`).join('');
  }

  /* ——— level flow ——— */
  function startLevel(i, skipCutscene, preserveGateState) {
    levelIdx = i; run.mistakesUsed = 0;
    if (!preserveGateState) gateFlawless = true;
    const L = LEVELS[i];
    const scr = $('#screen-level');
    scr.classList.toggle('ever', !!L.ever);
    $('#level-bg').style.backgroundImage = `url('${L.bg}')`;
    $('#ever-stars').innerHTML = L.ever
      ? Array.from({ length: 14 }, (_, k) => `<i style="left:${Math.random() * 100}%;top:${Math.random() * -20}%;animation-delay:${(Math.random() * 3.6).toFixed(2)}s;animation-duration:${(2.8 + Math.random() * 2).toFixed(2)}s"></i>`).join('')
      : '';
    const d = L.door, hs = $('#door-hotspot');
    hs.style.cssText = `left:${d.x}%;top:${d.y}%;width:${d.w * 19.2}px;height:${d.h * 10.8}px;display:none;`;
    const da = $('#door-anim');
    da.classList.remove('open', 'shut'); da.style.display = 'none';
    show('#screen-level'); renderHud();

    // ——— Worm flicker story beat ———
    // Gate 1: no flicker at all (calm).
    // Gate 2: one flicker on entry, baseline intensity.
    // Gate 3: one flicker on entry, a bit stronger/longer than gate 2.
    // Gate 4: one flicker on entry, the most intense — "Worm almost breaking through".
    // Gate 5: NO flicker — eerie stillness instead ("eye of the storm").
    // scheduleGateFlicker() (defined below) re-checks isCutscenePlaying right before firing,
    // and if the cutscene is still running it waits instead of silently skipping, so the
    // flicker always plays exactly once per gate, right after the player actually enters it.
    if (i === 1) {
      scheduleGateFlicker(1100, 'normal');
    } else if (i === 2) {
      scheduleGateFlicker(1600, 'normal');
    } else if (i === 3) {
      scheduleGateFlicker(2200, 'intense');
    } else if (i === 4) {
      applyEyeOfStorm(); // Gate 5: deliberately calm, no flicker
    }
    removeEyeOfStorm_unlessGate5(i);

    if (skipCutscene) showLevelCard(); else playCutscene(L, showLevelCard);
  }
  const DIFF_CLASS = { Low: 'low', Medium: 'med', Hard: 'hard' };
  function showLevelCard() {
    const i = levelIdx, L = LEVELS[i], hs = $('#door-hotspot');
    card(`
      <div class="lvl">Gate ${i + 1} of 5 · <span class="diff ${DIFF_CLASS[L.diff]}">${L.diff}</span></div>
      <h2>${L.name}</h2>
      <div class="jp" style="letter-spacing:.7em;">${L.jp}</div>
      <p>${L.brief}</p>
      <button class="btn primary" id="btn-approach">Approach the door</button>
    `);
    $('#btn-approach').onclick = () => { sfx.click(); hideCard(); hs.style.display = 'flex'; };
  }

  const YT_VIDEO_ID = '9pvsRHXPvA8';
  const ytPlayers = {};
  let ytApiReady = false;

  window.onYouTubeIframeAPIReady = function () {
    ytApiReady = true;
  };

  function getPlayer(id, onReady) {
    if (ytPlayers[id]) {
      if (onReady) onReady(ytPlayers[id]);
      return ytPlayers[id];
    }

    if (!ytApiReady) {
      setTimeout(() => getPlayer(id, onReady), 100);
      return null;
    }

    const p = new YT.Player(id, {
      videoId: YT_VIDEO_ID,
      playerVars: {
        playsinline: 1,
        controls: id === 'cs-vid' ? 0 : 1,
        rel: 0,
        disablekb: 1,
        modestbranding: 1
      },
      events: {
        onReady: (event) => {
          ytPlayers[id] = event.target;
          event.target.pauseVideo();
          if (onReady) onReady(event.target);
        },
        onStateChange: (event) => {
          if (event.target.onStateChangeCb) {
            event.target.onStateChangeCb(event);
          }
        }
      }
    });
    return p;
  }

  function handleVideoLoading(playerId, targetTime, onReadyCb) {
    const overlay = $('#video-loading-overlay');
    const msg = $('#vlo-msg');
    const err = $('#vlo-err');
    const retryBtn = $('#btn-retry-video');

    overlay.classList.add('on');
    msg.style.display = 'block';
    err.style.display = 'none';

    let timeoutId = setTimeout(() => {
      msg.style.display = 'none';
      err.style.display = 'block';
    }, 15000);

    const onPlayerReady = (player) => {
      let fallbackId = setTimeout(() => {
        if (player.getPlayerState() !== YT.PlayerState.PLAYING) {
          player.mute();
          player.playVideo();
        }
      }, 1000);

      player.onStateChangeCb = (event) => {
        if (event.data === YT.PlayerState.PLAYING) {
          clearTimeout(timeoutId);
          clearTimeout(fallbackId);
          overlay.classList.remove('on');
          if (onReadyCb) {
            const cb = onReadyCb;
            onReadyCb = null;
            cb(player);
          }
        }
      };

      player.unMute();
      player.seekTo(targetTime || 0, true);
      player.playVideo();

      retryBtn.onclick = () => {
        clearTimeout(timeoutId);
        clearTimeout(fallbackId);
        handleVideoLoading(playerId, targetTime, onReadyCb);
      };
    };

    getPlayer(playerId, onPlayerReady);
  }

  function playCutscene(L, cb) {
    isCutscenePlaying = true;

    // Pause any ongoing flicker animation if a cutscene starts mid-flicker
    const panel = document.querySelector('.game-panel-glow') || document.querySelector('#game-container') || document.querySelector('.game-container');
    if (panel) {
      panel.classList.remove('scary', 'scary-intense');
      panel.style.removeProperty('--scary-dur');
    }
    const overlay = document.getElementById('worm-overlay');
    if (overlay) overlay.classList.remove('active', 'intense');
    const sil = document.getElementById('worm-silhouette');
    if (sil) sil.classList.remove('active', 'intense');

    const cs = $('#cutscene'), clip = L.vid || { s: 0, e: 12 };
    $('#cs-cap').textContent = L.vidcap || '';

    handleVideoLoading('cs-vid', clip.s, (player) => {
      let ended = false;
      const endCutscene = () => {
        if (ended) return;
        ended = true;
        isCutscenePlaying = false;
        player.pauseVideo();
        if (player.pollInterval) clearInterval(player.pollInterval);
        cs.classList.remove('on');
        if (cb) cb();
      };

      if (player.pollInterval) clearInterval(player.pollInterval);
      player.pollInterval = setInterval(() => {
        if (player.getCurrentTime() >= clip.e) {
          endCutscene();
        }
      }, 100);

      cs.classList.add('on');

      $('#cs-skip').onclick = () => { sfx.click(); endCutscene(); };
    });
  }

  /* ——— door animation ——— */
  function playDoorOpen(cb) {
    const d = LEVELS[levelIdx].door, da = $('#door-anim');
    da.style.cssText = `left:${d.x}%;top:${d.y}%;width:${d.w * 19.2}px;height:${d.h * 10.8}px;display:block;`;
    da.classList.remove('open', 'shut'); void da.offsetWidth;
    sfx.creak(); da.classList.add('open');
    setTimeout(cb, 1600);
  }
  function playDoorClose(cb) {
    const da = $('#door-anim');
    if (da.style.display !== 'block') { cb(); return; }
    da.classList.add('shut'); da.classList.remove('open');
    setTimeout(() => { da.style.display = 'none'; da.classList.remove('shut'); cb(); }, 650);
  }

  $('#door-hotspot').addEventListener('click', () => {
    sfx.click(); $('#door-hotspot').style.display = 'none';
    openMinigame();
  });

  /* ——— minigame ——— */
  const MG_TITLES = {
    whisperSequence: 'Whisper Sequence Memory', daijin: 'Daijin Among Shadows', chair: 'Run, Little Chair',
    catrace: 'Water Mirror Rush', words: 'The Words of Closing', finale: 'The Last Lock',
    doorSymbol: 'Door Symbol Alignment', floodEscape: 'Flood Escape', mirrorWorld: 'Mirror World Navigation',
    puzzle: 'Spot The Difference', timeFreeze: 'Time Freeze Click', lightShadow: 'Light vs Shadow Puzzle',
    glitchMaze: 'Glitch Maze', fallingDebris: 'Falling Debris Dodge', sentenceBuild: 'Memory Reconstruction',
    soundHunt: 'Sound Direction Hunt', memoryTrail: 'Memory Trail Navigation', chaseRunner: 'Ruin Runner',
    finalRitual: 'The Final Ritual', realityChoiceDoor: 'Reality Choice Door', melodySeal: 'Melody of the Seal'
  };
  function openMinigame() {
    const L = LEVELS[levelIdx];
    const mgKey = run.selectedMinigames[levelIdx];
    $('#mg-overlay').classList.add('on');
    $('#mg-title').textContent = MG_TITLES[mgKey] || mgKey;
    $('#mg-stat').textContent = ''; $('#mg-instr').textContent = '';
    const body = $('#mg-body'); body.innerHTML = '';
    let settled = false;
    const ctx = {
      sfx,
      difficulty: run.difficulty,
      mode: run.hiddenMode,
      setStat: t => { $('#mg-stat').textContent = t; },
      setInstr: t => { $('#mg-instr').textContent = t; },
      win() { if (settled) return; settled = true; closeMinigame(); playDoorOpen(lockSequence); },
      fail() { if (settled) return; settled = true; closeMinigame(); failSequence(); }
    };
    mgCleanup = Minigames[mgKey](body, ctx);
  }
  function closeMinigame() {
    if (mgCleanup) { try { mgCleanup(); } catch (e) { } mgCleanup = null; }
    $('#mg-overlay').classList.remove('on');
    $('#mg-body').innerHTML = '';
  }

  /* ——— outcomes ——— */
  function lockSequence() {
    const L = LEVELS[levelIdx];
    runStats.gatesCleared = Math.max(runStats.gatesCleared, levelIdx + 1);
    if (gateFlawless) runStats.perfectDoors++;
    sfx.lock();
    const flash = $('#lock-flash');
    flash.style.transition = 'none'; flash.style.opacity = '.95';
    requestAnimationFrame(() => { flash.style.transition = 'opacity 1.2s ease'; flash.style.opacity = '0'; });
    const stamp = $('#lock-stamp');
    stamp.classList.remove('go'); void stamp.offsetWidth; stamp.classList.add('go');
    saveProgress(levelIdx + 1);
    setTimeout(() => {
      const last = levelIdx === LEVELS.length - 1;
      card(`
        <div class="lvl">Gate ${levelIdx + 1} opened</div>
        <p class="quote" style="font-size:34px;color:var(--ink);">“${L.quote}”</p>
        <button class="btn primary" id="btn-next">${last ? 'Step into the dawn' : 'Journey on'}</button>
      `);
      $('#btn-next').onclick = () => {
        sfx.click(); hideCard();
        if (last) { saveProgress(0); showVictory(); }
        else startLevel(levelIdx + 1);
      };
    }, 1700);
  }
  function failSequence() {
    runStats.fails++;
    runStats.mistakesSpent++;
    gateFlawless = false;
    run.mistakesUsed++; renderHud();
    const tint = $('#fail-tint'); tint.classList.add('on');
    setTimeout(() => tint.classList.remove('on'), 900);
    const remaining = run.mistakesAllowed - run.mistakesUsed;
    if (remaining > 0) {
      card(`
        <div style="display:flex;justify-content:center;">${CAT_HTML}</div>
        <div class="lvl" style="color:var(--danger);">The door held shut</div>
        <p>Every Closer gets turned away sometimes — even Souta. Take a breath; Daijin is rooting for you. ${remaining} ${remaining === 1 ? 'chance remains' : 'chances remain'}.</p>
        <button class="btn primary" id="btn-retry">Try again</button>
      `);
      $('#btn-retry').onclick = () => { sfx.click(); hideCard(); openMinigame(); };
    } else {
      card(`
        <div style="display:flex;justify-content:center;">${CAT_HTML}</div>
        <div class="lvl" style="color:var(--danger);">The door would not open</div>
        <p>Your charms are spent… but a Closer always comes back. The chair is packed, the door is waiting — let's try this gate once more.</p>
        <button class="btn primary" id="btn-restart">Return to the gate</button>
      `);
      $('#btn-restart').onclick = () => { sfx.click(); startLevel(levelIdx, true, true); };
    }
  }

  /* ——— victory ——— */
  function showVictory() {
    renderVictoryStats();
    show('#screen-victory');
    handleVideoLoading('victory-vid', 0, (player) => {
      // plays automatically
    });
  }
  $('#btn-again').addEventListener('click', () => { sfx.click(); const p = ytPlayers['victory-vid']; if (p) p.pauseVideo(); beginRun(false); startLevel(0); });
  $('#btn-title').addEventListener('click', () => { sfx.click(); const p = ytPlayers['victory-vid']; if (p) p.pauseVideo(); showTitle(); });

  /* ——— title ——— */
  function showTitle() {
    show('#screen-title');
    const p = loadProgress();
    $('#btn-continue').style.display = p > 0 && p < 5 ? 'inline-block' : 'none';
    $('#btn-continue').textContent = `Continue — Gate ${p + 1}`;
  }
  function firstGesture() {
    if (started) return; started = true;
    SuzumeAudio.unlock(); SuzumeAudio.ambientStart();
  }
  document.addEventListener('pointerdown', firstGesture, { once: false });
  $('#btn-start-easy').addEventListener('click', () => { firstGesture(); sfx.click(); saveProgress(0); beginRun(false, 'Easy'); startLevel(0); });
  $('#btn-start-med').addEventListener('click', () => { firstGesture(); sfx.click(); saveProgress(0); beginRun(false, 'Medium'); startLevel(0); });
  $('#btn-start-hard').addEventListener('click', () => { firstGesture(); sfx.click(); saveProgress(0); beginRun(false, 'Dangerous'); startLevel(0); });
  $('#btn-continue').addEventListener('click', () => { firstGesture(); sfx.click(); beginRun(true); startLevel(loadProgress()); });

  /* ——— video modal ——— */
  $('#btn-video').addEventListener('click', () => {
    sfx.click();
    $('#video-modal').classList.add('on');
    handleVideoLoading('modal-vid', 0, (player) => {
      // plays automatically
    });
  });
  $('#btn-close-video').addEventListener('click', () => {
    sfx.click(); const p = ytPlayers['modal-vid']; if (p) p.pauseVideo(); $('#video-modal').classList.remove('on');
  });

  /* ——— sound + quit ——— */
  function syncSound() {
    $('#btn-sound').textContent = 'Sound ' + (SuzumeAudio.isEnabled() ? 'On' : 'Off');
    const b = $('#btn-sound2'); if (b) b.textContent = 'Sound ' + (SuzumeAudio.isEnabled() ? 'On' : 'Off');
  }
  ['#btn-sound', '#btn-sound2'].forEach(s => {
    const b = $(s); if (b) b.addEventListener('click', () => {
      SuzumeAudio.setEnabled(!SuzumeAudio.isEnabled()); syncSound();
    });
  });
  $('#btn-quit').addEventListener('click', () => { closeMinigame(); hideCard(); $('#door-anim').style.display = 'none'; sfx.click(); showTitle(); });
  syncSound();

  showTitle();
  window.__suzume = { startLevel, showVictory, playDoorOpen, openMinigame };

  // ——— your own scream sound, embedded directly as base64 so no separate asset file is needed ———
  // Preloaded once so there is no playback delay the first time a gate flickers.
  const WORM_SCREAM_DATA_URI = "data:audio/mpeg;base64,";
  const wormScreamEl = new Audio(WORM_SCREAM_DATA_URI);
  wormScreamEl.preload = "auto";
  function playWormScream(volume) {
    if (!SuzumeAudio.isEnabled()) return; // respect the game's sound on/off toggle
    try {
      // Clone the node so overlapping triggers (e.g. quick re-entry) don't cut each other off.
      const node = wormScreamEl.cloneNode();
      node.volume = volume == null ? 0.85 : volume;
      node.play().catch(() => { /* autoplay can be blocked until the user has interacted once; ignore */ });
    } catch (e) { /* non-fatal — visuals still play even if audio fails */ }
  }

  function triggerScarySound(intensity) {
    // Layer 0: your uploaded scream — louder/more present on the intense (Gate 4) flicker.
    playWormScream(intensity === 'intense' ? 1.0 : 0.8);

    const audioCtx = new (window.AudioContext || window.webkitAudioContext)();
    const boost = intensity === 'intense' ? 1.35 : 1; // scales the synth layers below for Gate 4

    // Layer 1: Sub-bass rumble like the ground cracking open
    const sub = audioCtx.createOscillator();
    const subGain = audioCtx.createGain();
    sub.type = 'sine';
    sub.frequency.setValueAtTime(45, audioCtx.currentTime);
    sub.frequency.exponentialRampToValueAtTime(intensity === 'intense' ? 14 : 18, audioCtx.currentTime + 2.5);
    subGain.gain.setValueAtTime(0.9 * boost, audioCtx.currentTime);
    subGain.gain.exponentialRampToValueAtTime(0.001, audioCtx.currentTime + 2.5);
    sub.connect(subGain);
    subGain.connect(audioCtx.destination);
    sub.start();
    sub.stop(audioCtx.currentTime + 2.5);

    // Layer 2: Horror string stab - that sharp violin hit from horror movies
    const stab = audioCtx.createOscillator();
    const stabGain = audioCtx.createGain();
    const stabFilter = audioCtx.createBiquadFilter();
    stab.type = 'sawtooth';
    stab.frequency.setValueAtTime(220, audioCtx.currentTime);
    stab.frequency.exponentialRampToValueAtTime(110, audioCtx.currentTime + 1.2);
    stabFilter.type = 'bandpass';
    stabFilter.frequency.value = 800;
    stabFilter.Q.value = 0.8;
    stabGain.gain.setValueAtTime(0.0, audioCtx.currentTime);
    stabGain.gain.linearRampToValueAtTime(0.4 * boost, audioCtx.currentTime + 0.05);
    stabGain.gain.exponentialRampToValueAtTime(0.001, audioCtx.currentTime + 1.2);
    stab.connect(stabFilter);
    stabFilter.connect(stabGain);
    stabGain.connect(audioCtx.destination);
    stab.start();
    stab.stop(audioCtx.currentTime + 1.2);

    // Layer 3: Distorted growl like the Worm screaming
    const growl = audioCtx.createOscillator();
    const growlGain = audioCtx.createGain();
    const distortion = audioCtx.createWaveShaper();
    function makeDistortionCurve(amount) {
      const samples = 256;
      const curve = new Float32Array(samples);
      for (let i = 0; i < samples; i++) {
        const x = (i * 2) / samples - 1;
        curve[i] = ((Math.PI + amount) * x) / (Math.PI + amount * Math.abs(x));
      }
      return curve;
    }
    distortion.curve = makeDistortionCurve(intensity === 'intense' ? 160 : 100);
    distortion.oversample = '4x';

    growl.type = 'sawtooth';
    growl.frequency.setValueAtTime(65, audioCtx.currentTime);
    growl.frequency.linearRampToValueAtTime(intensity === 'intense' ? 28 : 35, audioCtx.currentTime + 1.8);
    growlGain.gain.setValueAtTime(0.0, audioCtx.currentTime);
    growlGain.gain.linearRampToValueAtTime(0.25 * boost, audioCtx.currentTime + 0.15);
    growlGain.gain.exponentialRampToValueAtTime(0.001, audioCtx.currentTime + 1.8);

    growl.connect(distortion);
    distortion.connect(growlGain);
    growlGain.connect(audioCtx.destination);
    growl.start();
    growl.stop(audioCtx.currentTime + 1.8);
  }

  /**
   * Fires the red flicker + silhouette + scream for the current gate.
   * intensity: 'normal' (Gate 2/3) or 'intense' (Gate 4, brighter red + bigger silhouette + louder/lower sound).
   */
  function triggerScaryFlash(durationMs = 1000, intensity = 'normal') {
    if (isCutscenePlaying) return;
    const panel = document.querySelector('.game-panel-glow') || document.querySelector('#game-container') || document.querySelector('.game-container');
    if (!panel) return;

    const isIntense = intensity === 'intense';

    panel.style.setProperty('--scary-dur', (durationMs / 1000) + 's');
    panel.classList.remove('scary', 'scary-intense');
    void panel.offsetWidth; // force reflow to restart animation
    panel.classList.add('scary');
    if (isIntense) panel.classList.add('scary-intense');

    // Trigger full screen red overlay
    const overlay = document.getElementById('worm-overlay');
    if (overlay) {
      overlay.classList.toggle('intense', isIntense);
      overlay.classList.add('active');
      setTimeout(() => overlay.classList.remove('active'), durationMs * 0.35); // brief flash relative to duration
    }

    // Trigger faint silhouette shadow
    const sil = document.getElementById('worm-silhouette');
    if (sil) {
      sil.classList.toggle('intense', isIntense);
      sil.classList.add('active');
      setTimeout(() => sil.classList.remove('active'), durationMs * (isIntense ? 0.4 : 0.3));
    }

    // Play scary sound (your uploaded scream + synth layers)
    triggerScarySound(intensity);

    setTimeout(() => {
      panel.classList.remove('scary', 'scary-intense');
      panel.style.removeProperty('--scary-dur');
    }, durationMs + 200); // clear after animation completes
  }

  /**
   * Schedules exactly ONE flicker for the gate the player just entered.
   * Unlike a plain setTimeout, this re-checks isCutscenePlaying right before firing:
   * if the cutscene is still running it polls and waits instead of silently dropping
   * the flicker, so every gate that should flicker, flickers — exactly once.
   */
  function scheduleGateFlicker(delayMs, intensity) {
    const gateAtSchedule = levelIdx; // guard against a quit/level-change firing the wrong gate's flicker
    const fire = () => {
      if (levelIdx !== gateAtSchedule) return; // player left this gate before it fired
      if (isCutscenePlaying) { setTimeout(fire, 200); return; } // wait out the cutscene, don't skip
      const durationMs = intensity === 'intense' ? 2200 : (delayMs >= 1500 ? 1500 : 1100);
      triggerScaryFlash(durationMs, intensity);
    };
    setTimeout(fire, delayMs);
  }

  /** Gate 5: eerie, unnaturally still — the opposite of a flicker. */
  function applyEyeOfStorm() {
    const panel = document.querySelector('.game-panel-glow');
    if (panel) panel.classList.add('calm-storm');
  }
  /** Clears Gate 5's calm-storm effect whenever we leave Gate 5 for any other gate. */
  function removeEyeOfStorm_unlessGate5(i) {
    if (i === 4) return;
    const panel = document.querySelector('.game-panel-glow');
    if (panel) panel.classList.remove('calm-storm');
  }
})();